import{_ as i,o as a,c as l,a2 as o}from"./chunks/framework.Fbjs98zA.js";const h=JSON.parse('{"title":"测试资产目录规范","description":"","frontmatter":{},"headers":[],"relativePath":"mango-pmo/rules/04-test-assets.md","filePath":"mango-pmo/rules/04-test-assets.md"}'),t={name:"mango-pmo/rules/04-test-assets.md"};function c(d,e,r,s,n,u){return a(),l("div",null,[...e[0]||(e[0]=[o('<h1 id="测试资产目录规范" tabindex="-1">测试资产目录规范 <a class="header-anchor" href="#测试资产目录规范" aria-label="Permalink to &quot;测试资产目录规范&quot;">​</a></h1><h2 id="_1-定位" tabindex="-1">1. 定位 <a class="header-anchor" href="#_1-定位" aria-label="Permalink to &quot;1. 定位&quot;">​</a></h2><ul><li>本文件约束测试代码、回归脚本、验收证据和临时测试产物的放置位置。</li><li>后端测试细节遵循 <code>rules/backend/08-test.md</code>。</li><li>前端测试细节遵循 <code>rules/frontend/04-test.md</code>。</li><li>临时运行目录遵循 <code>rules/02-dev-environment.md</code>。</li></ul><h2 id="_2-目录归属" tabindex="-1">2. 目录归属 <a class="header-anchor" href="#_2-目录归属" aria-label="Permalink to &quot;2. 目录归属&quot;">​</a></h2><ul><li>后端测试放到被测 Maven 模块的 <code>src/test/java</code> 或 <code>src/test/resources</code>。</li><li>后端跨模块能力链路放到约定的聚合测试模块，例如 <code>mango-infra-test</code> 或 app 模块。</li><li>前端应用 E2E 放到对应应用的 <code>e2e/specs</code>。</li><li>前端 E2E 公共 fixture、登录、接口和截图工具放到对应应用的 <code>e2e/support</code>。</li><li>前端包单测和组件测试放到对应包的 <code>src/__tests__</code>。</li><li>CLI 可复用测试放到 CLI 包内的 <code>tests</code> 或 <code>scripts</code>，不得长期放在 evidence 目录。</li><li>发布物料、企业项目初始化和模板消费类可重复回归脚本，应放到对应包或应用的正式测试目录。</li><li>正式交付需要 E2E 覆盖时，E2E 脚本必须沉淀到正式测试目录；只在 evidence 中保存一次性脚本副本不能作为长期交付入口。</li></ul><h2 id="_3-evidence-边界" tabindex="-1">3. Evidence 边界 <a class="header-anchor" href="#_3-evidence-边界" aria-label="Permalink to &quot;3. Evidence 边界&quot;">​</a></h2><ul><li><code>mango-docs/evidence/</code> 只保存某次验收的最终证据。</li><li>允许保存截图、报告、trace 摘要和可复核脚本副本。</li><li>允许保存测试结果基线，基线必须记录对应 E2E 脚本、命令、环境、数据集、账号/租户标识、结果摘要和报告路径。</li><li>禁止把生成项目、依赖缓存、构建产物、运行日志和临时下载文件放入 evidence。</li><li>可复用脚本在 evidence 中只能作为当次执行副本；长期入口必须沉淀到正式测试目录。</li></ul><h2 id="_4-runtime-边界" tabindex="-1">4. Runtime 边界 <a class="header-anchor" href="#_4-runtime-边界" aria-label="Permalink to &quot;4. Runtime 边界&quot;">​</a></h2><ul><li>测试生成的临时项目放到 <code>.runtime/projects/</code>。</li><li>测试包缓存放到 <code>.runtime/package-store/</code>。</li><li>测试日志、中间截图、下载文件、trace/video 原始产物放到 <code>.runtime/</code> 子目录。</li><li>任务结束后只把最终证据复制到 <code>mango-docs/evidence/</code>。</li><li><code>.runtime/</code> 内容不得提交。</li></ul><h2 id="_5-命名规则" tabindex="-1">5. 命名规则 <a class="header-anchor" href="#_5-命名规则" aria-label="Permalink to &quot;5. 命名规则&quot;">​</a></h2><ul><li>后端测试类使用 <code>XxxTest</code>、<code>XxxIntegrationTest</code> 或 <code>XxxE2ETest</code>。</li><li>前端测试文件使用 <code>*.spec.ts</code> 或 <code>*.test.ts</code>。</li><li>可复用脚本使用能表达目标的名称，例如 <code>main-framework-regression</code>、<code>enterprise-cli-runtime-regression</code>。</li><li>Evidence 目录使用日期和任务名命名，例如 <code>2026-06-04-main-framework-regression</code>。</li></ul><h2 id="_6-统一入口" tabindex="-1">6. 统一入口 <a class="header-anchor" href="#_6-统一入口" aria-label="Permalink to &quot;6. 统一入口&quot;">​</a></h2><ul><li>单模块测试可以使用模块原生命令。</li><li>跨模块回归必须提供明确命令入口。</li><li>主框架 E2E 入口应放在 <code>mango-ui/apps/mango-admin/e2e</code>。</li><li>微前端 E2E 入口应放在 <code>mango-ui/apps/mango-admin-shell/e2e</code>。</li><li>CLI 企业项目回归入口应放在 <code>mango-ui/packages/mango-cli/tests</code> 或 CLI 包脚本中。</li><li>后端全仓测试入口使用仓库 Maven 聚合命令。</li></ul><h2 id="_7-禁止事项" tabindex="-1">7. 禁止事项 <a class="header-anchor" href="#_7-禁止事项" aria-label="Permalink to &quot;7. 禁止事项&quot;">​</a></h2><ul><li>禁止把 evidence 目录当作长期测试脚本目录。</li><li>禁止把临时生成项目提交到仓库。</li><li>禁止把依赖缓存、构建产物或运行日志提交到仓库。</li><li>禁止只保留截图而没有可复核的验证步骤或报告。</li><li>禁止将同一个可复用回归脚本复制到多个长期目录。</li></ul>',15)])])}const _=i(t,[["render",c]]);export{h as __pageData,_ as default};
